import { Routes, Route, Link } from "react-router-dom";
import { useEffect, useState } from "react";
import CollegeDashboard from "./components/CollegeDashboard";
import Leaderboard from "./components/Leaderboard";
import PersonalGrowth from "./components/PersonalGrowth";
import CodeChefStats from "./components/CodeChefStats";
import UserSearch from "./components/UserSearch";
import Home from "./components/Home";
import Login from "./components/Login";
import Register from "./components/Register";
import AICoach from "./components/AICoach";
import Compare from "./components/Compare";
import { useAuth } from "./context/AuthContext";
// Enhanced UI Components
import EnhancedLeaderboard from "./components/EnhancedLeaderboard";
import EnhancedCodeChefStats from "./components/EnhancedCodeChefStats";
import ComparisonView from "./components/ComparisonView";
import OnboardingWizard from "./components/OnboardingWizard";
import StatsDashboard from "./components/StatsDashboard";
import ProblemOfTheDay from "./components/ProblemOfTheDay";
import ContestCalendar from "./components/ContestCalendar";
import Companies from "./components/Companies";
import CompanyDetails from "./components/CompanyDetails";

export default function App() {
  const [darkMode, setDarkMode] = useState(false);
  const [enhancedUI, setEnhancedUI] = useState(false);
  const { token, logout } = useAuth();

  /* ================= LOAD THEME ================= */
  useEffect(() => {
    const savedTheme = localStorage.getItem("theme");
    const savedUI = localStorage.getItem("enhancedUI");
    if (savedTheme === "dark") {
      setDarkMode(true);
      document.documentElement.classList.add("dark");
    }
    if (savedUI === "true") {
      setEnhancedUI(true);
    }
  }, []);

  /* ================= TOGGLE THEME ================= */
  const toggleDarkMode = () => {
    const next = !darkMode;
    setDarkMode(next);

    if (next) {
      document.documentElement.classList.add("dark");
      localStorage.setItem("theme", "dark");
    } else {
      document.documentElement.classList.remove("dark");
      localStorage.setItem("theme", "light");
    }
  };

  /* ================= TOGGLE ENHANCED UI ================= */
  const toggleEnhancedUI = () => {
    const next = !enhancedUI;
    setEnhancedUI(next);
    localStorage.setItem("enhancedUI", String(next));
  };

  return (
    <div className="min-h-screen bg-gray-100 text-gray-900 dark:bg-gray-900 dark:text-gray-100 transition-colors">
      {/* ================= NAVBAR ================= */}
      <nav className="sticky top-0 z-50 backdrop-blur-md bg-white/70 dark:bg-gray-900/70 border-b border-gray-200 dark:border-gray-800 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">
            {/* LEFT - Logo */}
            <div className="flex-shrink-0 flex items-center gap-2">
              <Link to="/" className="flex items-center gap-2 group">
                <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-blue-600 to-purple-600 flex items-center justify-center text-white font-bold text-lg shadow-lg group-hover:shadow-blue-500/30 transition-shadow">
                  C
                </div>
                <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-gray-900 to-gray-600 dark:from-white dark:to-gray-300">
                  CPulse
                </span>
              </Link>
            </div>

            {/* CENTER - Links (Hidden on mobile used to be, but keeping simple) */}
            <div className="hidden md:flex items-center gap-1">
              {[
                { to: "/search", label: "Search" },
                { to: "/leaderboard", label: "Ranking" },
                { to: "/compare", label: "Compare" },
                { to: "/problem-of-day", label: "Daily" },
                { to: "/companies", label: "Companies" },
                { to: "/contests", label: "Contests" },
              ].map((link) => (
                <Link
                  key={link.to}
                  to={link.to}
                  className="px-4 py-2 rounded-lg text-sm font-medium text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 hover:text-blue-600 dark:hover:text-blue-400 transition-all"
                >
                  {link.label}
                </Link>
              ))}

              {enhancedUI && (
                <Link
                  to="/dashboard"
                  className="px-4 py-2 rounded-lg text-sm font-medium text-purple-600 dark:text-purple-400 hover:bg-purple-50 dark:hover:bg-purple-900/20 transition-all"
                >
                  Stats
                </Link>
              )}
            </div>

            {/* RIGHT - Actions */}
            <div className="flex items-center gap-3">
              <button
                onClick={toggleEnhancedUI}
                className={`p-2 rounded-full transition-all ${enhancedUI
                  ? "bg-purple-100 dark:bg-purple-900/30 text-purple-600"
                  : "bg-gray-100 dark:bg-gray-800 text-gray-500 hover:bg-gray-200 dark:hover:bg-gray-700"
                  }`}
                title={enhancedUI ? "Switch to Classic" : "Switch to Enhanced"}
              >
                {enhancedUI ? "✨" : "⚡"}
              </button>

              <button
                onClick={toggleDarkMode}
                className="p-2 rounded-full bg-gray-100 dark:bg-gray-800 text-gray-500 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-700 transition"
                title="Toggle Theme"
              >
                {darkMode ? "☀️" : "🌙"}
              </button>

              {!token ? (
                <div className="flex items-center gap-2">
                  <Link
                    to="/login"
                    className="hidden sm:block px-4 py-2 rounded-lg text-sm font-medium text-gray-700 dark:text-gray-200 hover:bg-gray-100 dark:hover:bg-gray-800 transition"
                  >
                    Login
                  </Link>
                  <Link
                    to="/register"
                    className="px-4 py-2 rounded-lg text-sm font-medium bg-gradient-to-r from-blue-600 to-purple-600 text-white hover:opacity-90 shadow-md hover:shadow-lg transition-all"
                  >
                    Get Started
                  </Link>
                </div>
              ) : (
                <button
                  onClick={logout}
                  className="px-4 py-2 rounded-lg text-sm font-medium text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 transition"
                >
                  Logout
                </button>
              )}
            </div>
          </div>
        </div>
      </nav>

      {/* ================= MAIN CONTENT ================= */}
      <main className={`${enhancedUI ? "" : "max-w-6xl"} mx-auto p-6`}>
        <Routes>
          {/* Home */}
          <Route path="/" element={<Home />} />

          {/* Search */}
          <Route path="/search" element={<UserSearch />} />

          {/* Leaderboards - Classic vs Enhanced */}
          <Route
            path="/leaderboard"
            element={enhancedUI ? <EnhancedLeaderboard /> : <Leaderboard />}
          />
          <Route path="/college" element={<CollegeDashboard />} />

          {/* Personal Growth */}
          <Route
            path="/growth/:platform/:username"
            element={<PersonalGrowth />}
          />

          {/* CodeChef Stats - Classic vs Enhanced */}
          <Route
            path="/codechef/:username"
            element={enhancedUI ? <EnhancedCodeChefStats /> : <CodeChefStats />}
          />

          {/* Enhanced Features */}
          <Route path="/compare" element={<Compare />} />
          <Route path="/problem-of-day" element={<ProblemOfTheDay />} />
          <Route path="/contests" element={<ContestCalendar />} />

          {enhancedUI && (
            <>
              <Route path="/onboarding" element={<OnboardingWizard />} />
              <Route path="/dashboard" element={<StatsDashboard />} />
            </>
          )}

          {/* Companies */}
          <Route path="/companies" element={<Companies />} />
          <Route path="/companies/:slug" element={<CompanyDetails />} />

          {/* Auth */}
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />

          {/* Fallback */}
          <Route
            path="*"
            element={
              <div className="text-center text-gray-500 dark:text-gray-400 mt-20">
                <p className="text-lg">Page not found</p>
              </div>
            }
          />
        </Routes>
      </main>

      {/* CP Tutor (Floating) */}
